{ const items = []; $(list).find('li').each((j, item) => { const itemText = cleanText($(item).text()); if (itemText.length > 5) items.push('• ' + itemText); }); if (items.length > 0) lists.push(items.join('\n')); } }); const headings = []; const pageTitle = $('title').text().trim(); $('h1, h2, h3, h4').each((i, heading) => { const text = cleanText($(heading).text()); const tagName = $(heading).prop('tagName'); const level = parseInt(tagName.replace('H', '')); if (text && text.length > 3) headings.push({ level, text }); }); return { tables, relevantParagraphs, lists, headings, pageTitle }; }
