const items = $input.all();
for (const item of items) {
  if (!item.binary) continue;
  for (const key of Object.keys(item.binary)) {
    const bin = item.binary[key];
    try {
      // Check first 10 bytes for PDF magic header %PDF
      const buffer = Buffer.from(bin.data, 'base64');
      const header = buffer.slice(0, 10).toString('latin1');
      if (!header.startsWith('%PDF')) {
        const preview = header.replace(/[\x00-\x1F]/g, ' ').slice(0, 30);
        console.log(`[Validate PDF] Blocked - not a PDF. Header: "${preview}" | MIME: ${bin.mimeType}`);
        delete item.binary[key];
        item.json._pdf_blocked = true;
        item.json._pdf_block_reason = `Non-PDF response (header: ${preview})`;
      } else {
        console.log(`[Validate PDF] OK - valid PDF. MIME: ${bin.mimeType}`);
      }
    } catch(e) {
      console.log('[Validate PDF] Error reading binary:', e.message);
    }
  }
